@push('scripts')<script>function money(n){return 'Rs '+(Number(n)||0).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2})}function calc(){let sub=0,tax=0,total=0;$('#lineTable tbody tr').each(function(){let r=$(this),q=+r.find('[name="quantity[]"]').val()||0,p=+r.find('[name="unit_price[]"]').val()||0,d=+r.find('[name="discount_value[]"]').val()||0,dt=r.find('[name="discount_type[]"]').val(),tx=+r.find('[name="tax_percent[]"]').val()||0,b=q*p,da=dt==='flat'?d:b*d/100,g=Math.max(0,b-da),ta=tx?g*tx/(100+tx):0;sub+=g-ta;tax+=ta;total+=g});let od=+$('[name="discount_amount"]').val()||0;$('#uiSubtotal').text(money(sub));$('#uiTax').text(money(tax));$('#uiTotal').text(money(Math.max(0,total-od)))}function addLine(){ $('#lineTable tbody').append($('#lineTpl').html());calc() }$('#addLine').click(addLine);$(document).on('input change','#lineTable input,#lineTable select,[name="discount_amount"]',calc);$(document).on('click','.remove-row',function(){$(this).closest('tr').remove();calc()});$(document).on('change','.item-select',function(){let o=$(this).find(':selected'),r=$(this).closest('tr');r.find('[name="unit[]"]').val(o.data('unit'));r.find('[name="unit_price[]"]').val(o.data('price'));r.find('[name="tax_percent[]"]').val(o.data('tax')||18);calc()});if(!$('#lineTable tbody tr').length){addLine()}else{calc()}</script>@endpush
